import React from "react";
import { Route } from "@/types/route";
import { Link } from "react-router-dom";
import styles from "./RouteCard.module.css";

interface Props {
  route: Route;
}

const RouteCard: React.FC<Props> = ({ route }) => {
  // Map route color → CSS class
  const colorClass = route.name.toLowerCase().includes("gold")
    ? styles.gold
    : route.name.toLowerCase().includes("red")
    ? styles.red
    : styles.defaultRoute;

  return (
    <Link
      to={`/bus-routes?routeId=${route.id}`}
      className={`${styles.routeCard} ${colorClass}`}
    >
      <div className={styles.routeInfo}>
        <div className={styles.routeHeader}>
          <h2 className={styles.routeName}>{route.name}</h2>
          <span className={styles.badge}>Active</span>
        </div>

        <div
          className={styles.routeDetails}
          style={{
            display: "flex",
            gap: 12,
            alignItems: "center",
            flexWrap: "nowrap",
          }}
        >
          <div className={styles.detailItem} style={{ whiteSpace: "nowrap" }}>
            <strong>📍 Stops:</strong>&nbsp;{route.stops.length}
          </div>
          <div className={styles.detailItem} style={{ whiteSpace: "nowrap" }}>
            <strong>🚌 Buses:</strong>&nbsp;{route.busLocations?.length ?? 0}
          </div>
          <div className={styles.detailItem} style={{ whiteSpace: "nowrap" }}>
            <strong>⏱ Avg Delay:</strong>&nbsp;+2 min
          </div>
        </div>
      </div>

      <div className={styles.routeArrow}>→</div>
    </Link>
  );
};

export default RouteCard;
